import{_ as e,o as i,c as n,ag as t}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"Tentang Dotfiles (ID)","titleTemplate":":title","description":"Konfigurasi shell generasi berikutnya. Performa tinggi, aman, dan AI-native. Dikelola oleh Chezmoi. Kompatibel dengan macOS, Linux, dan WSL melalui Dotfiles.","frontmatter":{"title":"Tentang Dotfiles","description":"Konfigurasi shell generasi berikutnya. Performa tinggi, aman, dan AI-native. Dikelola oleh Chezmoi. Kompatibel dengan macOS, Linux, dan WSL melalui Dotfiles.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Tentang Dotfiles preview","canonical":"/id/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Tentang Dotfiles","pageType":"docs","schemaType":"WebPage","metaTitle":"Tentang Dotfiles - Dotfiles (ID)","permalink":"/id/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, konfigurasi, otomatisasi, macos, linux, rust, zellij, shell, terminal"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Konfigurasi shell generasi berikutnya. Performa tinggi, aman, dan AI-native. Dikelola oleh Chezmoi."},{"name":"twitter:title","content":"Tentang Dotfiles"},{"name":"og:title","content":"Tentang Dotfiles"},{"name":"og:description","content":"Konfigurasi shell generasi berikutnya. Performa tinggi, aman, dan AI-native. Dikelola oleh Chezmoi."},{"name":"og:image:alt","content":"Dotfiles - Dirancang sederhana untuk menyesuaikan kehidupan shell Anda"},{"name":"og:locale","content":"id_ID"}]},"headers":[],"relativePath":"id/about/index.md","filePath":"id/about/index.md","lastUpdated":1773010926000}'),l={name:"id/about/index.md"};function s(o,a,r,d,u,c){return i(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="tentang-dotfiles" tabindex="-1">Tentang Dotfiles <a class="header-anchor" href="#tentang-dotfiles" aria-label="Permalink to &quot;Tentang Dotfiles&quot;">​</a></h1><p>Standar modern untuk konfigurasi shell. Dibangun di atas <strong>Chezmoi</strong> untuk manajemen lingkungan lintas platform yang aman.</p><h2 id="temukan" tabindex="-1">Temukan <a class="header-anchor" href="#temukan" aria-label="Permalink to &quot;Temukan&quot;">​</a></h2><p>Dotfiles v0.2.495 mengubah terminal Anda menjadi ruang kerja yang kuat dan terpadu. Berbeda dengan dotfiles lama yang bergantung pada Makefile kompleks atau skrip symlink, Dotfiles menggunakan pendekatan berbasis template yang atomik, cepat, dan dapat direproduksi.</p><h3 id="yang-baru" tabindex="-1">Yang Baru <a class="header-anchor" href="#yang-baru" aria-label="Permalink to &quot;Yang Baru&quot;">​</a></h3><ul><li><strong>Inti Modern</strong> — Alternatif Rust berperforma tinggi menggantikan alat Unix lama: <ul><li><strong>Atuin</strong> untuk riwayat shell</li><li><strong>Yazi</strong> untuk manajemen file</li><li><strong>Zellij</strong> untuk multiplexing terminal</li><li><strong>Ghostty</strong> untuk terminal dengan akselerasi GPU</li><li><strong>NeoVim</strong> untuk pengeditan modern</li></ul></li><li><strong>Keamanan Native</strong> — Penandatanganan SSH native sepenuhnya tanpa agen pihak ketiga</li><li><strong>Mode Interaktif</strong> — Perintah <code>dot learn</code> baru memandu Anda melalui fitur-fitur</li></ul><h2 id="mulai" tabindex="-1">Mulai <a class="header-anchor" href="#mulai" aria-label="Permalink to &quot;Mulai&quot;">​</a></h2><h3 id="persyaratan" tabindex="-1">Persyaratan <a class="header-anchor" href="#persyaratan" aria-label="Permalink to &quot;Persyaratan&quot;">​</a></h3><ul><li><strong>macOS</strong>, <strong>Linux (Ubuntu/Debian)</strong>, atau <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> dan <strong>Git</strong></li><li><strong>Chezmoi</strong> (diinstal secara otomatis)</li><li><strong>Nerd Font</strong> (untuk ikon terminal)</li></ul><h3 id="instalasi" tabindex="-1">Instalasi <a class="header-anchor" href="#instalasi" aria-label="Permalink to &quot;Instalasi&quot;">​</a></h3><p>Jalankan satu perintah untuk menginstal seluruh suite:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>Installer akan:</p><ol><li>Menginstal binary <code>chezmoi</code></li><li>Mengkloning repositori</li><li>Menginstal paket yang diperlukan melalui Homebrew (macOS) atau Apt (Linux)</li><li>Menerapkan konfigurasi Anda</li></ol><h3 id="jelajahi" tabindex="-1">Jelajahi <a class="header-anchor" href="#jelajahi" aria-label="Permalink to &quot;Jelajahi&quot;">​</a></h3><p>Setelah instalasi, restart terminal Anda dan jalankan:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>Ini meluncurkan tur interaktif lingkungan baru Anda.</p><h2 id="sesuaikan" tabindex="-1">Sesuaikan <a class="header-anchor" href="#sesuaikan" aria-label="Permalink to &quot;Sesuaikan&quot;">​</a></h2><p>Konfigurasi Anda berada di <code>~/.local/share/chezmoi</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # Titik masuk shell</span></span>
<span class="line"><span>├── dot_config/             # XDG Base Config (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # Riwayat shell</span></span>
<span class="line"><span>│   ├── ghostty/            # Emulator terminal</span></span>
<span class="line"><span>│   ├── git/                # Konfigurasi Git</span></span>
<span class="line"><span>│   ├── yazi/               # Manajer file</span></span>
<span class="line"><span>│   ├── zellij/             # Multiplexer terminal</span></span>
<span class="line"><span>│   ├── zsh/                # Konfigurasi Zsh</span></span>
<span class="line"><span>│   └── shell/              # Alias dan path bersama</span></span>
<span class="line"><span>├── provision/              # Skrip siklus hidup</span></span>
<span class="line"><span>├── install.sh              # Installer universal</span></span>
<span class="line"><span>└── docs/                   # Dokumentasi</span></span></code></pre></div><h2 id="kontribusi" tabindex="-1">Kontribusi <a class="header-anchor" href="#kontribusi" aria-label="Permalink to &quot;Kontribusi&quot;">​</a></h2><p>Bergabunglah dengan komunitas. Tinjau <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">Kode Etik</a> dan <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">Panduan Kontribusi</a> kami.</p><h2 id="perintah-inti" tabindex="-1">Perintah inti <a class="header-anchor" href="#perintah-inti" aria-label="Permalink to &quot;Perintah inti&quot;">​</a></h2><p>CLI <code>dot</code> menyediakan 53 perintah yang diorganisir berdasarkan kategori.</p><h3 id="inti" tabindex="-1">Inti <a class="header-anchor" href="#inti" aria-label="Permalink to &quot;Inti&quot;">​</a></h3><ul><li><code>dot apply</code> — menerapkan perubahan konfigurasi.</li><li><code>dot sync</code> — mengambil status repo terbaru dan menerapkannya.</li><li><code>dot update</code> — memperbarui repo dan menghangatkan cache.</li><li><code>dot add</code> — menambahkan file baru ke sumber Chezmoi.</li><li><code>dot diff</code> — menampilkan perubahan yang tertunda sebelum diterapkan.</li><li><code>dot status</code> — menampilkan status file yang dikelola.</li><li><code>dot remove</code> — menghapus file dari pengelolaan dan menghapus entri sumber.</li><li><code>dot cd</code> — membuka shell di direktori sumber Chezmoi.</li><li><code>dot edit</code> — membuka file yang dikelola di editor Anda.</li><li><code>dot clean-cache</code> — membersihkan cache sementara.</li><li><code>dot prewarm</code> — mengisi cache terlebih dahulu untuk startup shell yang lebih cepat.</li></ul><h3 id="diagnostik" tabindex="-1">Diagnostik <a class="header-anchor" href="#diagnostik" aria-label="Permalink to &quot;Diagnostik&quot;">​</a></h3><ul><li><code>dot doctor</code> — memvalidasi path, alat, dan status shell.</li><li><code>dot heal</code> — memperbaiki status yang hilang atau rusak secara otomatis.</li><li><code>dot health</code> — menjalankan pemeriksaan kesehatan ringan.</li><li><code>dot verify</code> — memeriksa integritas file terhadap sumber.</li><li><code>dot scorecard</code> — menampilkan skor kualitas konfigurasi.</li><li><code>dot snapshot</code> — menangkap status saat ini untuk perbandingan nanti.</li><li><code>dot smoke-test</code> — memvalidasi toolchain inti secara end-to-end.</li><li><code>dot chaos</code> — menyuntikkan kesalahan untuk menguji penyembuhan diri.</li><li><code>dot bundle</code> — mengekspor bundel konfigurasi portabel.</li><li><code>dot rollback</code> — mengembalikan ke snapshot sebelumnya.</li><li><code>dot drift</code> — mendeteksi perubahan tak terduga pada file yang dikelola.</li><li><code>dot history</code> — menampilkan log riwayat apply/sync.</li><li><code>dot benchmark</code> — mengukur waktu startup shell.</li><li><code>dot perf</code> — memprofilkan inisialisasi shell yang lambat.</li></ul><h3 id="tampilan" tabindex="-1">Tampilan <a class="header-anchor" href="#tampilan" aria-label="Permalink to &quot;Tampilan&quot;">​</a></h3><ul><li><code>dot theme</code> — mengubah skema warna terminal.</li><li><code>dot wallpaper</code> — mengatur wallpaper desktop (macOS).</li><li><code>dot fonts</code> — menginstal atau memperbarui Nerd Fonts.</li><li><code>dot tune</code> — menyesuaikan kepadatan UI dan gaya prompt.</li></ul><h3 id="keamanan" tabindex="-1">Keamanan <a class="header-anchor" href="#keamanan" aria-label="Permalink to &quot;Keamanan&quot;">​</a></h3><ul><li><code>dot backup</code> — membuat cadangan konfigurasi terenkripsi.</li><li><code>dot encrypt-check</code> — memverifikasi enkripsi rahasia saat disimpan.</li><li><code>dot firewall</code> — mengonfigurasi aturan firewall host.</li><li><code>dot telemetry</code> — mengontrol telemetri penggunaan anonim.</li><li><code>dot dns-doh</code> — mengaktifkan DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — mengunci layar segera.</li><li><code>dot usb-safety</code> — membatasi auto-mount penyimpanan massal USB.</li></ul><h3 id="rahasia" tabindex="-1">Rahasia <a class="header-anchor" href="#rahasia" aria-label="Permalink to &quot;Rahasia&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — menginisialisasi backend rahasia (age / GPG).</li><li><code>dot secrets</code> — menampilkan daftar entri rahasia terenkripsi.</li><li><code>dot secrets-create</code> — membuat rahasia terenkripsi baru.</li><li><code>dot ssh-key</code> — menghasilkan atau merotasi pasangan kunci SSH.</li><li><code>dot ssh-cert</code> — meminta sertifikat SSH dari CA.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — membuka sesi asisten AI interaktif.</li><li><code>dot ai-setup</code> — mengonfigurasi kunci API untuk penyedia AI.</li><li><code>dot ai-query</code> — mengirim prompt sekali pakai ke model AI.</li><li>Wrapper alat AI: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="alat" tabindex="-1">Alat <a class="header-anchor" href="#alat" aria-label="Permalink to &quot;Alat&quot;">​</a></h3><ul><li><code>dot tools</code> — menampilkan pengganti CLI yang disertakan dan statusnya.</li><li><code>dot new</code> — membuat file alias atau fungsi baru.</li><li><code>dot sandbox</code> — membuka shell sandbox sekali pakai.</li><li><code>dot keys</code> — menampilkan binding tombol saat ini.</li><li><code>dot learn</code> — memulai tutorial interaktif.</li></ul><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><ul><li><code>dot upgrade</code> — memperbarui Dotfiles ke rilis terbaru.</li><li><code>dot packages</code> — menampilkan paket yang diinstal yang dikelola oleh Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — menampilkan informasi versi atau penggunaan</li></ul>`,41)])])}const p=e(l,[["render",s]]);export{h as __pageData,p as default};
